import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"24. Termination Of Employment","description":"","frontmatter":{"title":"24. Termination Of Employment","eba":"Allied Health Professionals 2021-2026","topics":["employment","termination"]},"headers":[],"relativePath":"ebas/allied-health/employment/24-termination-of-employment.md","filePath":"ebas/allied-health/employment/24-termination-of-employment.md"}'),i={name:"ebas/allied-health/employment/24-termination-of-employment.md"};function r(l,e,s,m,p,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_24-termination-of-employment" tabindex="-1">24. Termination Of Employment <a class="header-anchor" href="#_24-termination-of-employment" aria-label="Permalink to &quot;24. Termination Of Employment&quot;">​</a></h1><p>NOTE: this clause 24 only applies to full-time and part-time Employees unless otherwise indicated.</p><p><strong>24.1</strong> In the event of termination of employment, four (4) weeks’ written notice must be given by the Employer.</p><p><strong>24.2</strong> The notice required by subclause 24.1 will be increased by one (1) week if the Employee is over 45 years of age and has completed at least two (2) years of continuous service.</p><p><strong>24.3</strong> An Employer may make payment in lieu of notice for part or all of the notice period. The payment in lieu of notice must equal or exceed the total of all amounts that the Employer would have paid had the Employee’s employment continued until the end of the required notice period, including superannuation. That payment must be calculated on the basis of:</p><p><strong>(a)</strong> the Employee’s ordinary hours of work (even if not standard hours);</p><p><strong>(b)</strong> the amounts ordinarily payable to the Employee in respect of those hours, including (for example) allowances, loading and penalties; and</p><p><strong>(c)</strong> any other amounts payable under the Employee&#39;s contract of employment.</p><p><strong>24.4</strong> An Employee (including a fixed term Employee) may terminate their employment by providing four (4) weeks’ notice to the Employer in writing. Subject to financial obligations imposed on the Employer by any legislation, if an Employee fails to give notice the Employer will have the right to withhold monies due to the Employee with a maximum amount equal to the ordinary time rate of pay for the period of notice not provided by the Employee.</p><p><strong>24.5</strong> Subclauses 24.1 to 24.3 do not affect an Employer&#39;s right to terminate an Employee&#39;s employment without notice for serious misconduct (as defined for the purposes of the Act).</p><p><strong>24.6</strong> Subclause 48.4 deals with payments or deductions related to ADOs upon termination.</p><p><strong>24.7</strong> Where the Employer has given notice of termination to an Employee, an Employee will be allowed:</p><p><strong>(a)</strong> if the termination is a result of redundancy, up to one (1) day off without loss of pay during each week of notice for the purpose of seeking other employment; or</p><p><strong>(b)</strong> if the notice of termination is for any reason other than redundancy, up to one (1) day off without loss of pay for the purpose of seeking other employment at times that are convenient to the Employee after consultation with the Employer.</p><p>Plain language terms: resignation, dismissal.</p>',15)])])}const f=t(i,[["render",r]]);export{d as __pageData,f as default};
